"""
Python - Comandos de controle condicional

if, else e alif -> (else if)

"""
x = 5
y = 5

if y > x:
    print("y é maior do que x")
elif y < x:
    print("y é menor do que x")
else:
    print("y não é menor nem maior que x")

print("Código fora do bloco condicional")
print(y > x)
print(y < x)
print(y == x)
